  1	import * as React from 'react';
  2	import {
  3	  Button,
  4	  ButtonVariant,
  5	  TextInput,
  6	  Tooltip,
  7	  Form,
  8	  FormHelperText,
  9	  Grid,
 10	  HelperText,
 11	  HelperTextItem,
 12	  FormGroup,
 13	  GridItem
 14	} from '@patternfly/react-core';
 15	import { Controller, Graph, GraphElement } from '@patternfly/react-topology';
 16	import { connect } from 'react-redux';
 17	import { bindActionCreators } from 'redux';
 18	import { KialiAppState } from '../../../store/Store';
 19	import { meshFindValueSelector, meshHideValueSelector } from '../../../store/Selectors';
 20	import { KialiIcon } from 'config/KialiIcon';
 21	import { kialiStyle } from 'styles/StyleUtils';
 22	import { TourStop } from 'components/Tour/TourStop';
 23	import { MeshTourStops } from 'pages/Mesh/MeshHelpTour';
 24	import { KialiDispatch } from 'types/Redux';
 25	import { AutoComplete } from 'utils/AutoComplete';
 26	import { HEALTHY, NA, NOT_READY } from 'types/Health';
 27	import { location, HistoryManager, URLParam } from '../../../app/History';
 28	import { isValid } from 'utils/Common';
 29	import {
 30	  setObserved,
 31	  elems,
 32	  SelectAnd,
 33	  SelectExp,
 34	  selectOr,
 35	  SelectOr,
 36	  descendents,
 37	  toSafeFieldName
 38	} from 'helpers/GraphHelpers';
 39	import { isArray } from 'lodash';
 40	import { MeshAttr, MeshEdgeData, MeshInfraType, MeshNodeData } from 'types/Mesh';
 41	import { MeshToolbarActions } from 'actions/MeshToolbarActions';
 42	import { MeshFindOptions } from './MeshFindOptions';
 43	import { MeshHelpFind } from '../MeshHelpFind';
 44	import { layoutMesh } from '../Mesh';
 45	import { infoStyle } from 'styles/IconStyle';
 46	import { MeshLayoutType, MeshLayout } from '../layouts/layoutFactory';
 47	
 48	type ReduxStateProps = {
 49	  findValue: string;
 50	  hideValue: string;
 51	  layout: MeshLayout;
 52	  showFindHelp: boolean;
 53	};
 54	
 55	type ReduxDispatchProps = {
 56	  setFindValue: (val: string) => void;
 57	  setHideValue: (val: string) => void;
 58	  toggleFindHelp: () => void;
 59	};
 60	
 61	type MeshFindProps = ReduxStateProps &
 62	  ReduxDispatchProps & {
 63	    controller?: Controller;
 64	    elementsChanged: boolean;
 65	  };
 66	
 67	type MeshFindState = {
 68	  findError?: string;
 69	  findInputValue: string;
 70	  hideError?: string;
 71	  hideInputValue: string;
 72	};
 73	
 74	type ParsedExpression = {
 75	  selector: SelectExp | SelectAnd | SelectOr;
 76	  target: 'node' | 'edge';
 77	};
 78	
 79	const thinGroupStyle = kialiStyle({
 80	  paddingLeft: '0.75rem'
 81	});
 82	
 83	const buttonClearStyle = kialiStyle({
 84	  paddingLeft: '0.75rem',
 85	  paddingRight: '0.75rem'
 86	});
 87	
 88	const findHideHelpStyle = kialiStyle({
 89	  paddingLeft: '0',
 90	  paddingRight: '0'
 91	});
 92	
 93	const gridStyle = kialiStyle({
 94	  display: 'flex'
 95	});
 96	
 97	const meshFindStyle = kialiStyle({
 98	  marginRight: '0.75rem',
 99	  $nest: {
100	    '& > .pf-v6-c-form__group-control': {
101	      display: 'flex'
102	    }
103	  }
104	});
105	
106	const meshHideStyle = kialiStyle({
107	  $nest: {
108	    '& > .pf-v6-c-form__group-control': {
109	      display: 'flex'
110	    }
111	  }
112	});
113	
114	const operands: string[] = ['cluster', 'healthy', 'inaccessible', 'name', 'namespace', 'infratype'];
115	
116	export class MeshFindComponent extends React.Component<MeshFindProps, MeshFindState> {
117	  static contextTypes = {
118	    router: (): null => null
119	  };
120	
121	  private findAutoComplete: AutoComplete;
122	  private findInputRef;
123	  private findElements: GraphElement[] | undefined;
124	  private hiddenElements: GraphElement[] | undefined;
125	  private hideAutoComplete: AutoComplete;
126	  private hideInputRef;
127	
128	  constructor(props: MeshFindProps) {
129	    super(props);
130	
131	    this.findAutoComplete = new AutoComplete(operands);
132	    this.hideAutoComplete = new AutoComplete(operands);
133	
134	    let findValue = props.findValue ? props.findValue : '';
135	    let hideValue = props.hideValue ? props.hideValue : '';
136	
137	    // Let URL override current redux state at construction time. Update URL as needed.
138	    const urlParams = new URLSearchParams(location.getSearch());
139	    const urlFind = HistoryManager.getParam(URLParam.MESH_FIND, urlParams);
140	
141	    if (urlFind) {
142	      if (urlFind !== findValue) {
143	        findValue = urlFind;
144	        props.setFindValue(urlFind);
145	      }
146	    } else if (findValue) {
147	      HistoryManager.setParam(URLParam.MESH_FIND, findValue);
148	    }
149	
150	    const urlHide = HistoryManager.getParam(URLParam.MESH_HIDE, urlParams);
151	
152	    if (urlHide) {
153	      if (urlHide !== hideValue) {
154	        hideValue = urlHide;
155	        props.setHideValue(urlHide);
156	      }
157	    } else if (hideValue) {
158	      HistoryManager.setParam(URLParam.MESH_HIDE, hideValue);
159	    }
160	
161	    this.state = { findInputValue: findValue, hideInputValue: hideValue };
162	
163	    if (props.showFindHelp) {
164	      props.toggleFindHelp();
165	    }
166	  }
167	
168	  // We only update on a change to the find/hide values, or a mesh change.  Although we use other props
169	  // in processing (layout, etc), a change to those settings will generate a mesh change, so we
170	  // wait for the mesh change to do the update.
171	  shouldComponentUpdate(nextProps: MeshFindProps, nextState: MeshFindState): boolean {
172	    const controllerChanged = this.props.controller !== nextProps.controller;
173	    const elementsChanged = !this.props.elementsChanged && nextProps.elementsChanged;
174	    const findChanged = this.props.findValue !== nextProps.findValue;
175	    const hideChanged = this.props.hideValue !== nextProps.hideValue;
176	    const showFindHelpChanged = this.props.showFindHelp !== nextProps.showFindHelp;
177	    const findErrorChanged = this.state.findError !== nextState.findError;
178	    const hideErrorChanged = this.state.hideError !== nextState.hideError;
179	
180	    const shouldUpdate =
181	      controllerChanged ||
182	      elementsChanged ||
183	      findChanged ||
184	      hideChanged ||
185	      showFindHelpChanged ||
186	      findErrorChanged ||
187	      hideErrorChanged;
188	
189	    return shouldUpdate;
190	  }
191	
192	  // Note that we may have redux hide/find values set at mount-time. But because the toolbar mounts prior to
193	  // the mesh loading, we can't perform this mesh "post-processing" until we have a valid controller.  But the
194	  // find/hide processing will be initiated externally (processMeshUpdate) when the mesh is ready.
195	  componentDidUpdate(prevProps: MeshFindProps): void {
196	    if (!this.props.controller) {
197	      this.findElements = undefined;
198	      this.hiddenElements = undefined;
199	      return;
200	    }
201	
202	    const controllerChanged = this.props.controller !== prevProps.controller;
203	    const elementsChanged = this.props.elementsChanged && !prevProps.elementsChanged;
204	    const findChanged = this.props.findValue !== prevProps.findValue;
205	    const hideChanged = this.props.hideValue !== prevProps.hideValue;
206	
207	    // ensure redux state and URL are aligned
208	    if (findChanged) {
209	      if (!this.props.findValue) {
210	        HistoryManager.deleteParam(URLParam.MESH_FIND);
211	      } else {
212	        HistoryManager.setParam(URLParam.MESH_FIND, this.props.findValue);
213	      }
214	    }
215	    if (hideChanged) {
216	      if (!this.props.hideValue) {
217	        HistoryManager.deleteParam(URLParam.MESH_HIDE);
218	      } else {
219	        HistoryManager.setParam(URLParam.MESH_HIDE, this.props.hideValue);
220	      }
221	    }
222	
223	    // make sure the value is updated if there was a change
224	    if (controllerChanged || findChanged || (elementsChanged && this.props.findValue)) {
225	      // ensure findInputValue is aligned if findValue is set externally (e.g. resetSettings)
226	      if (this.state.findInputValue !== this.props.findValue) {
227	        this.setFind(this.props.findValue);
228	      }
229	
230	      this.handleFind(this.props.controller);
231	    }
232	
233	    if (controllerChanged || hideChanged || (elementsChanged && this.props.hideValue)) {
234	      // ensure hideInputValue is aligned if hideValue is set externally (e.g. resetSettings)
235	      if (this.state.hideInputValue !== this.props.hideValue) {
236	        this.setHide(this.props.hideValue);
237	      }
238	      this.handleHide(this.props.controller);
239	    }
240	  }
241	
242	  render(): React.ReactNode {
243	    return (
244	      <TourStop info={MeshTourStops.Find}>
245	        <Form className={thinGroupStyle}>
246	          <Grid md={12} className={gridStyle}>
247	            <GridItem span={5}>
248	              <FormGroup>
249	                <TextInput
250	                  id="MESH_FIND"
251	                  name="MESH_FIND"
252	                  ref={ref => {
253	                    this.findInputRef = ref;
254	                  }}
255	                  type="text"
256	                  autoComplete="on"
257	                  validated={isValid(this.state.findInputValue ? !this.state.findError : undefined)}
258	                  onChange={(_event, val) => this.updateFind(val)}
259	                  defaultValue={this.state.findInputValue}
260	                  onKeyDownCapture={this.checkSpecialKeyFind}
261	                  placeholder="Find..."
262	                />
263	                {this.state.findError && (
264	                  <FormHelperText>
265	                    <HelperText>
266	                      <HelperTextItem variant={'error'}>{this.state.findError}</HelperTextItem>
267	                    </HelperText>
268	                  </FormHelperText>
269	                )}
270	              </FormGroup>
271	            </GridItem>
272	
273	            <GridItem span={1}>
274	              <FormGroup className={meshFindStyle}>
275	                <MeshFindOptions kind="find" onSelect={this.updateFindOption} />
276	                {this.props.findValue && (
277	                  <Tooltip key="ot_clear_find" position="top" content="Clear Find...">
278	                    <Button
279	                      className={buttonClearStyle}
280	                      variant={ButtonVariant.control}
281	                      onClick={() => this.setFind('')}
282	                    >
283	                      <KialiIcon.Close />
284	                    </Button>
285	                  </Tooltip>
286	                )}
287	              </FormGroup>
288	            </GridItem>
289	
290	            <GridItem span={5}>
291	              <FormGroup>
292	                <TextInput
293	                  id="MESH_HIDE"
294	                  name="MESH_HIDE"
295	                  ref={ref => {
296	                    this.hideInputRef = ref;
297	                  }}
298	                  autoComplete="on"
299	                  validated={isValid(this.state.hideInputValue ? !this.state.hideError : undefined)}
300	                  type="text"
301	                  onChange={(_event, val) => this.updateHide(val)}
302	                  defaultValue={this.state.hideInputValue}
303	                  onKeyDownCapture={this.checkSpecialKeyHide}
304	                  placeholder="Hide..."
305	                />
306	                {this.state.hideError && (
307	                  <FormHelperText>
308	                    <HelperText>
309	                      <HelperTextItem variant={'error'}>{this.state.hideError}</HelperTextItem>
310	                    </HelperText>
311	                  </FormHelperText>
312	                )}
313	              </FormGroup>
314	            </GridItem>
315	
316	            <GridItem span={1}>
317	              <FormGroup className={meshHideStyle}>
318	                <MeshFindOptions kind="hide" onSelect={this.updateHideOption} />
319	                {this.props.hideValue && (
320	                  <Tooltip key="ot_clear_hide" position="top" content="Clear Hide...">
321	                    <Button
322	                      className={buttonClearStyle}
323	                      variant={ButtonVariant.control}
324	                      onClick={() => this.setHide('')}
325	                    >
326	                      <KialiIcon.Close />
327	                    </Button>
328	                  </Tooltip>
329	                )}
330	              </FormGroup>
331	            </GridItem>
332	          </Grid>
333	        </Form>
334	
335	        {this.props.showFindHelp ? (
336	          <MeshHelpFind onClose={this.toggleFindHelp}>
337	            <Button
338	              data-test="mesh-find-hide-help-button"
339	              variant={ButtonVariant.link}
340	              className={findHideHelpStyle}
341	              onClick={this.toggleFindHelp}
342	            >
343	              <KialiIcon.Info className={infoStyle} />
344	            </Button>
345	          </MeshHelpFind>
346	        ) : (
347	          <Tooltip key={'ot_mesh_find_help'} position="top" content="Click to open Find/Hide help">
348	            <Button
349	              data-test="mesh-find-hide-help-button"
350	              variant={ButtonVariant.link}
351	              className={findHideHelpStyle}
352	              onClick={this.toggleFindHelp}
353	            >
354	              <KialiIcon.Info className={infoStyle} />
355	            </Button>
356	          </Tooltip>
357	        )}
358	      </TourStop>
359	    );
360	  }
361	
362	  private toggleFindHelp = (): void => {
363	    this.props.toggleFindHelp();
364	  };
365	
366	  private checkSpecialKeyFind = (event: React.KeyboardEvent): void => {
367	    const keyCode = event.keyCode ? event.keyCode : event.which;
368	    switch (keyCode) {
369	      case 9: // tab (autocomplete)
370	        event.preventDefault();
371	        const next = this.findAutoComplete.next();
372	
373	        if (next) {
374	          this.findInputRef.value = next;
375	          this.findInputRef.scrollLeft = this.findInputRef.scrollWidth;
376	          this.setState({ findInputValue: next, findError: undefined });
377	        }
378	
379	        break;
380	      case 13: // return (submit)
381	        event.preventDefault();
382	        this.submitFind();
383	        break;
384	      default:
385	        break;
386	    }
387	  };
388	
389	  private updateFindOption = (key: string): void => {
390	    this.setFind(key);
391	  };
392	
393	  private updateFind = (val: string): void => {
394	    if ('' === val) {
395	      this.setFind('');
396	    } else {
397	      const diff = Math.abs(val.length - this.state.findInputValue.length);
398	      this.findAutoComplete.setInput(val, [' ', '!']);
399	      this.setState({ findInputValue: val, findError: undefined });
400	
401	      // submit if length change is greater than a single key, assume browser suggestion clicked or user paste
402	      if (diff > 1) {
403	        this.props.setFindValue(val);
404	      }
405	    }
406	  };
407	
408	  private setFind = (val: string): void => {
409	    // TODO: when TextInput refs are fixed in PF4 then use the ref and remove the direct HTMLElement usage
410	    this.findInputRef.value = val;
411	    const htmlInputElement: HTMLInputElement = document.getElementById('MESH_FIND') as HTMLInputElement;
412	
413	    if (htmlInputElement !== null) {
414	      htmlInputElement.value = val;
415	    }
416	
417	    this.findAutoComplete.setInput(val);
418	    this.setState({ findInputValue: val, findError: undefined });
419	    this.props.setFindValue(val);
420	  };
421	
422	  private submitFind = (): void => {
423	    if (this.props.findValue !== this.state.findInputValue) {
424	      this.props.setFindValue(this.state.findInputValue);
425	    }
426	  };
427	
428	  private checkSpecialKeyHide = (event: React.KeyboardEvent): void => {
429	    const keyCode = event.keyCode ? event.keyCode : event.which;
430	    switch (keyCode) {
431	      case 9: // tab (autocomplete)
432	        event.preventDefault();
433	        const next = this.hideAutoComplete.next();
434	
435	        if (next) {
436	          this.hideInputRef.value = next;
437	          this.hideInputRef.scrollLeft = this.hideInputRef.scrollWidth;
438	          this.setState({ hideInputValue: next, hideError: undefined });
439	        }
440	
441	        break;
442	      case 13: // return (submit)
443	        event.preventDefault();
444	        this.submitHide();
445	        break;
446	      default:
447	        break;
448	    }
449	  };
450	
451	  private updateHideOption = (key: string): void => {
452	    this.setHide(key);
453	  };
454	
455	  private updateHide = (val: string): void => {
456	    if ('' === val) {
457	      this.setHide('');
458	    } else {
459	      const diff = Math.abs(val.length - this.state.hideInputValue.length);
460	      this.hideAutoComplete.setInput(val, [' ', '!']);
461	      this.setState({ hideInputValue: val, hideError: undefined });
462	
463	      // submit if length change is greater than a single key, assume browser suggestion clicked or user paste
464	      if (diff > 1) {
465	        this.props.setHideValue(val);
466	      }
467	    }
468	  };
469	
470	  private submitHide = (): void => {
471	    if (this.props.hideValue !== this.state.hideInputValue) {
472	      this.props.setHideValue(this.state.hideInputValue);
473	    }
474	  };
475	
476	  private setHide = (val: string): void => {
477	    // TODO: when TextInput refs are fixed in PF4 then use the ref and remove the direct HTMLElement usage
478	    this.hideInputRef.value = val;
479	    const htmlInputElement: HTMLInputElement = document.getElementById('MESH_HIDE') as HTMLInputElement;
480	
481	    if (htmlInputElement !== null) {
482	      htmlInputElement.value = val;
483	    }
484	
485	    this.hideAutoComplete.setInput(val);
486	    this.setState({ hideInputValue: val, hideError: undefined });
487	    this.props.setHideValue(val);
488	  };
489	
490	  // All edges have the graph as a parent
491	  private unhideElements = (g: Graph, elems: GraphElement[]): void => {
492	    setObserved(() => {
493	      elems.forEach(e => {
494	        e.setVisible(true);
495	
496	        if (!e.hasParent()) {
497	          g.appendChild(e);
498	        }
499	      });
500	    });
501	  };
502	
503	  private handleHide = (controller: Controller): void => {
504	    const selector = this.parseValue(this.props.hideValue, false);
505	    const checkRemovals = selector.nodeSelector || selector.edgeSelector;
506	    const mesh = controller.getGraph();
507	
508	    console.debug(`Mesh Hide selector=[${JSON.stringify(selector)}]`);
509	
510	    // unhide any currently hidden elements, something changed so we'll redetermine what needs to be hidden
511	    if (this.hiddenElements) {
512	      this.unhideElements(mesh, this.hiddenElements);
513	    }
514	    this.hiddenElements = undefined;
515	
516	    // select the new hide-hits
517	    if (checkRemovals) {
518	      let hiddenNodes = [] as GraphElement[];
519	      let hiddenEdges = [] as GraphElement[];
520	      const { nodes, edges } = elems(controller);
521	
522	      // add elements described by the hide expression
523	      if (selector.nodeSelector) {
524	        hiddenNodes = selectOr(nodes, selector.nodeSelector);
525	        setObserved(() => hiddenNodes.forEach(n => n.setVisible(false)));
526	      }
527	      if (selector.edgeSelector) {
528	        hiddenEdges = selectOr(edges, selector.edgeSelector);
529	        setObserved(() => hiddenEdges.forEach(e => e.setVisible(false)));
530	      }
531	      if (hiddenEdges.length > 0) {
532	        // also hide nodes with only hidden edges (keep idle nodes as that is an explicit option)
533	        setObserved(() => {
534	          nodes.forEach(n => {
535	            if (n.isVisible()) {
536	              const nodeData = n.getData();
537	              const nodeEdges = n.getSourceEdges().concat(n.getTargetEdges());
538	              if (!nodeData.isIdle && nodeEdges.length > 0 && nodeEdges.every(e => !e.isVisible())) {
539	                n.setVisible(false);
540	              }
541	            }
542	          });
543	        });
544	      }
545	
546	      // also hide edges connected to hidden nodes
547	      setObserved(() => {
548	        edges.forEach(e => {
549	          if (e.isVisible() && !(e.getSource().isVisible() && e.getTarget().isVisible())) {
550	            e.setVisible(false);
551	          }
552	        });
553	      });
554	
555	      // unhide any box hits, we only hide empty boxes
556	      this.unhideElements(
557	        mesh,
558	        nodes.filter(n => n.isGroup() && !n.isVisible())
559	      );
560	
561	      // now hide any boxes that don't have any visible children
562	      setObserved(() => {
563	        nodes
564	          .filter(n => n.isGroup())
565	          .forEach(g => {
566	            if (descendents(g).every(d => !d.isVisible())) {
567	              g.setVisible(false);
568	            }
569	          });
570	      });
571	
572	      const finalNodes = nodes.filter(n => !n.isVisible()) as GraphElement[];
573	      const finalEdges = edges.filter(e => !e.isVisible()) as GraphElement[];
574	
575	      this.hiddenElements = finalNodes.concat(finalEdges);
576	    }
577	
578	    // always perform a full layout, because if this function is invoked at all, we know either we're dealing with either
579	    // a new controller, a different topology, a new hide expression, etc
580	    layoutMesh(controller, MeshLayoutType.Layout);
581	  };
582	
583	  private handleFind = (controller: Controller): void => {
584	    const selector = this.parseValue(this.props.findValue, true);
585	    console.debug(`Mesh Find selector=[${JSON.stringify(selector)}]`);
586	
587	    // unhighlight old find-hits
588	    setObserved(() => {
589	      this.findElements?.forEach(e => {
590	        const data = e.getData() as MeshNodeData | MeshEdgeData;
591	        e.setData({ ...data, isFind: false });
592	      });
593	    });
594	
595	    this.findElements = undefined;
596	
597	    // add new find-hits
598	    if (selector.nodeSelector || selector.edgeSelector) {
599	      const { nodes, edges } = elems(controller);
600	      let findNodes = [] as GraphElement[];
601	      let findEdges = [] as GraphElement[];
602	
603	      if (selector.nodeSelector) {
604	        findNodes = selectOr(nodes, selector.nodeSelector);
605	      }
606	
607	      if (selector.edgeSelector) {
608	        findEdges = selectOr(edges, selector.edgeSelector);
609	      }
610	
611	      this.findElements = findNodes.concat(findEdges);
612	      setObserved(() => {
613	        this.findElements?.forEach(e => {
614	          const data = e.getData() as MeshNodeData | MeshEdgeData;
615	          e.setData({ ...data, isFind: true });
616	        });
617	      });
618	    }
619	  };
620	
621	  private setError(error: string | undefined, isFind: boolean): undefined {
622	    if (isFind && error !== this.state.findError) {
623	      const findError = error ? `Find: ${error}` : undefined;
624	      this.setState({ findError: findError });
625	    } else if (error !== this.state.hideError) {
626	      const hideError = error ? `Hide: ${error}` : undefined;
627	      this.setState({ hideError: hideError });
628	    }
629	
630	    return undefined;
631	  }
632	
633	  private parseValue = (
634	    val: string,
635	    isFind: boolean
636	  ): { edgeSelector: SelectOr | undefined; nodeSelector: SelectOr | undefined } => {
637	    let preparedVal = this.prepareValue(val);
638	    if (!preparedVal) {
639	      return { nodeSelector: undefined, edgeSelector: undefined };
640	    }
641	
642	    // generate separate selectors for each disjunctive clause and then stitch them together. This
643	    // lets us mix node and edge criteria.
644	    const orClauses = preparedVal.split(' OR ');
645	    let orNodeSelector: SelectOr = [];
646	    let orEdgeSelector: SelectOr = [];
647	
648	    for (const clause of orClauses) {
649	      const expressions = clause.split(' AND ');
650	      const conjunctive = expressions.length > 1;
651	      let nodeSelector: SelectAnd = [];
652	      let edgeSelector: SelectAnd = [];
653	      let target;
654	
655	      for (const expression of expressions) {
656	        const parsedExpression = this.parseExpression(expression, conjunctive, isFind);
657	        if (!parsedExpression) {
658	          return { nodeSelector: undefined, edgeSelector: undefined };
659	        }
660	
661	        if (!target) {
662	          target = parsedExpression.target;
663	        } else if (target !== parsedExpression.target) {
664	          this.setError('Invalid expression. Can not AND node and edge criteria.', isFind);
665	          return { nodeSelector: undefined, edgeSelector: undefined };
666	        }
667	
668	        const selector = parsedExpression.selector;
669	        if (target === 'node') {
670	          // special case, selector is a SelectAnd or SelectOr
671	          if (isArray(selector)) {
672	            // if 'selector' is already a SelectOr then directly add to orSelector
673	            if (isArray(selector[0])) {
674	              orNodeSelector.push(...(selector as SelectAnd[]));
675	            } else {
676	              nodeSelector.push(...(selector as SelectExp[]));
677	            }
678	          } else {
679	            nodeSelector.push(selector as SelectExp);
680	          }
681	        } else {
682	          edgeSelector.push(parsedExpression.selector as SelectExp);
683	        }
684	      }
685	
686	      // parsed successfully, clear any previous error message
687	      this.setError(undefined, isFind);
688	      if (nodeSelector.length > 0) {
689	        orNodeSelector.push(nodeSelector);
690	      }
691	      if (edgeSelector.length > 0) {
692	        orEdgeSelector.push(edgeSelector);
693	      }
694	    }
695	
696	    return { nodeSelector: orNodeSelector, edgeSelector: orEdgeSelector };
697	  };
