699	  private prepareValue = (val: string): string => {
700	    // remove double spaces
701	    val = val.replace(/ +(?= )/g, '');
702	
703	    // remove unnecessary mnemonic qualifiers on unary operators (e.g. 'has cb' -> 'cb').
704	    val = ` ${val}`;
705	    val = val.replace(/ is /gi, ' ');
706	    val = val.replace(/ has /gi, ' ');
707	    val = val.replace(/ !\s*is /gi, ' ! ');
708	    val = val.replace(/ !\s*has /gi, ' ! ');
709	
710	    // replace string operators
711	    val = val.replace(/ not /gi, ' !');
712	    val = val.replace(/ !\s*contains /gi, ' !*= ');
713	    val = val.replace(/ !\s*startswith /gi, ' !^= ');
714	    val = val.replace(/ !\s*endswith /gi, ' !$= ');
715	    val = val.replace(/ contains /gi, ' *= ');
716	    val = val.replace(/ startswith /gi, ' ^= ');
717	    val = val.replace(/ endswith /gi, ' $= ');
718	
719	    // uppercase conjunctions
720	    val = val.replace(/ and /gi, ' AND ');
721	    val = val.replace(/ or /gi, ' OR ');
722	
723	    return val.trim();
724	  };
