726	  private parseExpression = (
727	    expression: string,
728	    _conjunctive: boolean,
729	    isFind: boolean
730	  ): ParsedExpression | undefined => {
731	    let op;
732	
733	    if (expression.includes('!=')) {
734	      op = '!=';
735	    } else if (expression.includes('!*=')) {
736	      op = '!*=';
737	    } else if (expression.includes('!$=')) {
738	      op = '!$=';
739	    } else if (expression.includes('!^=')) {
740	      op = '!^=';
741	    } else if (expression.includes('>=')) {
742	      op = '>=';
743	    } else if (expression.includes('<=')) {
744	      op = '<=';
745	    } else if (expression.includes('*=')) {
746	      op = '*='; // substring
747	    } else if (expression.includes('$=')) {
748	      op = '$='; // starts with
749	    } else if (expression.includes('^=')) {
750	      op = '^='; // ends with
751	    } else if (expression.includes('=')) {
752	      op = '=';
753	    } else if (expression.includes('>')) {
754	      op = '>';
755	    } else if (expression.includes('<')) {
756	      op = '<';
757	    } else if (expression.includes('!')) {
758	      op = '!';
759	    }
760	
761	    if (!op) {
762	      if (expression.split(' ').length > 1) {
763	        return this.setError(`No valid operator found in expression`, isFind);
764	      }
765	
766	      const unaryExpression = this.parseUnaryFindExpression(expression.trim(), false);
767	      return unaryExpression ? unaryExpression : this.setError(`Invalid Node or Edge operand`, isFind);
768	    }
769	
770	    const tokens = expression.split(op);
771	
772	    if (op === '!') {
773	      const unaryExpression = this.parseUnaryFindExpression(tokens[1].trim(), true);
774	      return unaryExpression ? unaryExpression : this.setError(`Invalid Node or Edge operand`, isFind);
775	    }
776	
777	    const field = tokens[0].trim();
778	    const val = tokens[1].trim();
779	
780	    switch (field.toLowerCase()) {
781	      //
782	      // nodes...
783	      //
784	      case 'cluster':
785	        return { target: 'node', selector: { prop: MeshAttr.cluster, op: op, val: val } };
786	      case 'name': {
787	        return { target: 'node', selector: { prop: MeshAttr.infraName, op: op, val: val } };
788	      }
789	      case 'ns':
790	      case 'namespace':
791	        return { target: 'node', selector: { prop: MeshAttr.namespace, op: op, val: val } };
792	      case 'type':
793	      case 'infratype':
794	        let infraType = val.toLowerCase();
795	        switch (infraType) {
796	          case MeshInfraType.DATAPLANE:
797	          case MeshInfraType.GRAFANA:
798	          case MeshInfraType.ISTIOD:
799	          case MeshInfraType.KIALI:
800	            return { target: 'node', selector: { prop: MeshAttr.infraType, op: op, val: infraType } };
801	          case MeshInfraType.METRIC_STORE:
802	          case 'ms':
803	          case 'prom':
804	          case 'prometheus':
805	            return { target: 'node', selector: { prop: MeshAttr.infraType, op: op, val: MeshInfraType.METRIC_STORE } };
806	          case MeshInfraType.TRACE_STORE:
807	          case 'ts':
808	          case 'jaeger':
809	          case 'tempo':
810	            return { target: 'node', selector: { prop: MeshAttr.infraType, op: op, val: MeshInfraType.TRACE_STORE } };
811	          default:
812	            this.setError(
813	              `Invalid infra type [${infraType}]. Expected dataplane | istiod | kiali | metricStore | traceStore`,
814	              isFind
815	            );
816	        }
817	        return undefined;
818	      //
819	      // edges..
820	      // currently N/A
821	      //
822	      default:
823	        // special node operand
824	        if (field.startsWith('label:')) {
825	          return {
826	            target: 'node',
827	            selector: { prop: toSafeFieldName(field), op: op, val: val }
828	          };
829	        }
830	
831	        return this.setError(`Invalid operand [${field}]`, isFind);
832	    }
833	  };
834	
835	  /*
836	  private getNumericSelector(
837	    field: string,
838	    op: string,
839	    val: any,
840	    _expression: string,
841	    isFind: boolean
842	  ): SelectExp | undefined {
843	    switch (op) {
844	      case '>':
845	      case '<':
846	      case '>=':
847	      case '<=':
848	        if (isNaN(val)) {
849	          return this.setError(`Invalid value [${val}]. Expected a numeric value (use '.' for decimals)`, isFind);
850	        }
851	        return { prop: field, op: op, val: val };
852	      case '=':
853	        if (isNaN(val)) {
854	          return { prop: field, op: 'falsy' };
855	        }
856	        return { prop: field, op: op, val: val };
857	      case '!=':
858	        if (isNaN(val)) {
859	          return { prop: field, op: 'truthy' };
860	        }
861	        return { prop: field, op: op, val: val };
862	      default:
863	        return this.setError(`Invalid operator [${op}] for numeric condition`, isFind);
864	    }
865	  }
866	  */
867	
868	  private parseUnaryFindExpression = (field: string, isNegation): ParsedExpression | undefined => {
869	    switch (field.toLowerCase()) {
870	      //
871	      // nodes...
872	      //
873	      case 'inaccessible':
874	        return {
875	          target: 'node',
876	          selector: { prop: MeshAttr.isInaccessible, op: isNegation ? 'falsy' : 'truthy' }
877	        };
878	      case 'healthy':
879	        return {
880	          target: 'node',
881	          selector: isNegation
882	            ? [
883	                { prop: MeshAttr.healthStatus, op: '!=', val: HEALTHY.name },
884	                { prop: MeshAttr.healthStatus, op: '!=', val: NA.name },
885	                { prop: MeshAttr.healthStatus, op: '!=', val: NOT_READY.name }
886	              ]
887	            : { prop: MeshAttr.healthStatus, val: HEALTHY.name }
888	        };
889	      //
890	      // edges...
891	      //
892	      case 'mtls':
893	        return { target: 'edge', selector: { prop: MeshAttr.isMTLS, op: isNegation ? '<=' : '>', val: 0 } };
894	      default:
895	        // special node operand
896	        if (field.startsWith('label:')) {
897	          const safeFieldName = toSafeFieldName(field);
898	          return { target: 'node', selector: { prop: safeFieldName, op: isNegation ? '<=' : '>', val: 0 } };
899	        }
900	
901	        return undefined;
902	    }
903	  };
904	}
